function BottomNav({ activeTab, setActiveTab }) {
  return (
    <nav className="fixed inset-x-0 bottom-4 z-40 mx-auto flex max-w-md justify-center px-4">
      <div className="relative flex w-full items-center justify-between rounded-full border border-[#DDD7C8] bg-white/70 px-2 py-2 backdrop-blur-xl">
        {tabs.map((tab) => {
          const Icon = tab.icon;
          const isActive = tab.id === activeTab;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className="relative z-10 flex w-14 flex-col items-center justify-center py-1"
            >
              <span
                className={`absolute h-9 w-9 rounded-full transition-all duration-500 ${
                  isActive ? 'scale-100 bg-[#1C1917]' : 'scale-0'
                }`}
              />
              <Icon className={`relative h-4 w-4 ${isActive ? 'text-white' : 'text-[#5B5348]'}`} />
              <span className={`relative mt-1 text-[10px] ${isActive ? 'text-[#1C1917]' : 'text-[#7A7266]'}`}>{tab.label}</span>
            </button>
          );
        })}
      </div>
    </nav>
  );
}

